export type AABenchmarkEntry = {
  readonly "agentic_index": number | null
  readonly "coding_index": number | null
  readonly "intelligence_index": number | null
}
export const AABenchmarkEntry = Schema.Struct({
  "agentic_index": Schema.Union([
    Schema.Number.check(Schema.isFinite().annotate({ "expected": "a finite number" })),
    Schema.Null
  ]).annotate({ "description": "Artificial Analysis Agentic Index score", "format": "double" }),
  "coding_index": Schema.Union([
    Schema.Number.check(Schema.isFinite().annotate({ "expected": "a finite number" })),
    Schema.Null
  ]).annotate({ "description": "Artificial Analysis Coding Index score", "format": "double" }),
  "intelligence_index": Schema.Union([
    Schema.Number.check(Schema.isFinite().annotate({ "expected": "a finite number" })),
    Schema.Null
  ]).annotate({ "description": "Artificial Analysis Intelligence Index score", "format": "double" })
}).annotate({ "description": "Artificial Analysis benchmark index scores.", "identifier": "AABenchmarkEntry" })
export type ActivityItem = {
  readonly "byok_usage_inference": number
  readonly "completion_tokens": number
  readonly "date": string
  readonly "endpoint_id": string
  readonly "model": string
  readonly "model_permaslug": string
  readonly "prompt_tokens": number
  readonly "provider_name": string
  readonly "reasoning_tokens": number
  readonly "requests": number
  readonly "usage": number
}
export const ActivityItem = Schema.Struct({
  "byok_usage_inference": Schema.Number.annotate({
    "description": "BYOK inference cost in USD (external credits spent)",
    "format": "double"
  }).check(Schema.isFinite().annotate({ "expected": "a finite number" })),
  "completion_tokens": Schema.Number.annotate({ "description": "Total completion tokens generated" }).check(
    Schema.isInt().annotate({ "expected": "an integer" })
  ),
  "date": Schema.String.annotate({ "description": "Date of the activity (YYYY-MM-DD format)" }),
  "endpoint_id": Schema.String.annotate({ "description": "Unique identifier for the endpoint" }),
  "model": Schema.String.annotate({ "description": "Model slug (e.g., \"openai/gpt-4.1\")" }),
  "model_permaslug": Schema.String.annotate({ "description": "Model permaslug (e.g., \"openai/gpt-4.1-2025-04-14\")" }),
  "prompt_tokens": Schema.Number.annotate({ "description": "Total prompt tokens used" }).check(
    Schema.isInt().annotate({ "expected": "an integer" })
  ),
  "provider_name": Schema.String.annotate({ "description": "Name of the provider serving this endpoint" }),
  "reasoning_tokens": Schema.Number.annotate({ "description": "Total reasoning tokens used" }).check(
    Schema.isInt().annotate({ "expected": "an integer" })
  ),
  "requests": Schema.Number.annotate({ "description": "Number of requests made" }).check(
    Schema.isInt().annotate({ "expected": "an integer" })
  ),
  "usage": Schema.Number.annotate({ "description": "Total cost in USD (OpenRouter credits spent)", "format": "double" })
    .check(Schema.isFinite().annotate({ "expected": "a finite number" }))
}).annotate({ "identifier": "ActivityItem" })
