export type ImageGenerationRequest = {
  readonly "aspect_ratio"?:
    | "1:1"
    | "1:2"
    | "1:4"
    | "1:8"
    | "2:1"
    | "2:3"
    | "3:2"
    | "3:4"
    | "4:1"
    | "4:3"
    | "4:5"
    | "5:4"
    | "8:1"
    | "9:16"
    | "16:9"
    | "9:19.5"
    | "19.5:9"
    | "9:20"
    | "20:9"
    | "9:21"
    | "21:9"
    | "auto"
  readonly "background"?: "auto" | "transparent" | "opaque"
  readonly "input_references"?: ReadonlyArray<ContentPartImage>
  readonly "model": string
  readonly "n"?: number
  readonly "output_compression"?: number
  readonly "output_format"?: "png" | "jpeg" | "webp" | "svg"
  readonly "prompt": string
  readonly "provider"?: ImageGenerationProviderPreferences
  readonly "quality"?: "auto" | "low" | "medium" | "high"
  readonly "resolution"?: "512" | "1K" | "2K" | "4K"
  readonly "seed"?: number
  readonly "size"?: string
  readonly "stream"?: boolean
}
export const ImageGenerationRequest = Schema.Struct({
  "aspect_ratio": Schema.optionalKey(
    Schema.Literals([
      "1:1",
      "1:2",
      "1:4",
      "1:8",
      "2:1",
      "2:3",
      "3:2",
      "3:4",
      "4:1",
      "4:3",
      "4:5",
      "5:4",
      "8:1",
      "9:16",
      "16:9",
      "9:19.5",
      "19.5:9",
      "9:20",
      "20:9",
      "9:21",
      "21:9",
      "auto"
    ]).annotate({
      "description": "Normalized aspect ratio of the generated image. Providers clamp to their supported subset."
    })
  ),
  "background": Schema.optionalKey(
    Schema.Literals(["auto", "transparent", "opaque"]).annotate({
      "description": "Background treatment. `transparent` requires an output_format that supports alpha (png or webp)."
    })
  ),
  "input_references": Schema.optionalKey(
    Schema.Array(ContentPartImage).annotate({
      "description": "Reference images to guide image-to-image generation, as base64 data URLs or HTTP(S) URLs."
    }).check(Schema.isMaxLength(16).annotate({ "expected": "a value with a length of at most 16" }))
  ),
  "model": Schema.String.annotate({ "description": "The image generation model to use" }),
  "n": Schema.optionalKey(
    Schema.Number.annotate({
      "description":
        "Number of images to generate (1-10). Providers that only support single-image generation reject n > 1."
    }).check(Schema.isInt().annotate({ "expected": "an integer" }))
  ),
  "output_compression": Schema.optionalKey(
    Schema.Number.annotate({
      "description":
        "Compression level (0-100) for webp/jpeg output. Ignored for png and by providers without a compression knob."
    }).check(Schema.isInt().annotate({ "expected": "an integer" }))
  ),
  "output_format": Schema.optionalKey(
    Schema.Literals(["png", "jpeg", "webp", "svg"]).annotate({
      "description":
        "Encoding of the returned image bytes. Most models produce raster formats (png, jpeg, webp). SVG is supported by vectorization models (e.g. Quiver) — the SVG markup is UTF-8 base64-encoded in `b64_json`."
    })
  ),
  "prompt": Schema.String.annotate({ "description": "Text description of the desired image" }).check(
    Schema.isMinLength(1).annotate({ "expected": "a value with a length of at least 1" })
  ),
  "provider": Schema.optionalKey(ImageGenerationProviderPreferences),
  "quality": Schema.optionalKey(
    Schema.Literals(["auto", "low", "medium", "high"]).annotate({
      "description": "Rendering quality. Providers without a quality knob ignore this."
    })
  ),
  "resolution": Schema.optionalKey(
    Schema.Literals(["512", "1K", "2K", "4K"]).annotate({
      "description":
        "Normalized resolution tier of the generated image. Concrete pixel dimensions are derived per-provider."
    })
  ),
  "seed": Schema.optionalKey(
    Schema.Number.annotate({
      "description":
        "If specified, the generation will sample deterministically, such that repeated requests with the same seed and parameters should return the same result. Determinism is not guaranteed for all providers."
    }).check(Schema.isInt().annotate({ "expected": "an integer" }))
  ),
  "size": Schema.optionalKey(Schema.String.annotate({
    "description":
      "Optional. A convenience shorthand for output dimensions — pass a tier (\"2K\", \"4K\") or explicit pixels (\"2048x2048\") and we normalize it to the right dimensions for the chosen provider. A tier size is equivalent to setting `resolution` and combines with `aspect_ratio`. An explicit pixel size is authoritative: a mismatched `resolution` or `aspect_ratio` alongside it is rejected with a 400."
  })),
  "stream": Schema.optionalKey(
    Schema.Boolean.annotate({
      "description":
        "If true, partial images are streamed as SSE events as they become available. Only supported by providers with native streaming (currently OpenAI). Non-streaming providers ignore this flag and return a buffered response."
    })
  )
}).annotate({ "description": "Image generation request input", "identifier": "ImageGenerationRequest" })
